onClick:
{{
  (() => {
    const row = ListeAffaires.triggeredRow;

    if (!row) {
      showAlert("Aucune affaire sélectionnée", "warning");
      return;
    }

    SupprimerAffaire.run({ numero_affaire: row.numero_affaire })
      .then(() => {
        showAlert(`Affaire ${row.numero_affaire} supprimée ✅`, "success");
        return GetAffaires.run();
      })
      .then(() => {
        closeModal(ModalSuppressionAffaire.name);
      })
      .catch((e) => {
        console.log("Erreur suppression affaire", e);
        showAlert("Erreur lors de la suppression de l'affaire", "error");
      });
  })()
}}
